The code below is a complete, single-file HTML solution. It uses **Three.js** (a popular 3D library) to render a procedural house.

You can save this code as an `.html` file (e.g., `house.html`) and open it in any modern web browser.

### Features included:
*   **Procedural Generation:** The house is built using code (no external image models required).
*   **Lighting:** Includes ambient light and a directional sun.
*   **Interactivity:** You can **rotate** (left click + drag), **zoom** (scroll wheel), and **pan** (right click + drag).
*   **Animation:** The sun rotates slowly to simulate time passing.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate | Scroll to Zoom</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. SCENE SETUP
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // 2. CONTROLS
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 2, 0);

        // 3. LIGHTING
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1.5);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. MATERIALS
        const materials = {
            wall: new THREE.MeshStandardMaterial({ color: 0xeeeeee, roughness: 0.8 }),
            roof: new THREE.MeshStandardMaterial({ color: 0x8B4513, roughness: 0.9 }),
            window: new THREE.MeshStandardMaterial({ color: 0x87CEEB, roughness: 0.1, metalness: 0.1 }),
            door: new THREE.MeshStandardMaterial({ color: 0x5c3a21, roughness: 0.8 }),
            grass: new THREE.MeshStandardMaterial({ color: 0x4caf50 })
        };

        // 5. BUILDING THE HOUSE
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, materials.wall);
        floor.position.y = 0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Walls
        const wallHeight = 4;
        const wallGeo = new THREE.BoxGeometry(10, wallHeight, 1);
        const wall1 = new THREE.Mesh(wallGeo, materials.wall);
        wall1.position.set(0, wallHeight / 2 + 0.5, 5);
        wall1.castShadow = true;
        wall1.receiveShadow = true;
        houseGroup.add(wall1);

        const wall2 = new THREE.Mesh(wallGeo, materials.wall);
        wall2.position.set(0, wallHeight / 2 + 0.5, -5);
        wall2.castShadow = true;
        wall2.receiveShadow = true;
        houseGroup.add(wall2);

        const wall3 = new THREE.Mesh(wallGeo, materials.wall);
        wall3.position.set(5, wallHeight / 2 + 0.5, 0);
        wall3.castShadow = true;
        wall3.receiveShadow = true;
        houseGroup.add(wall3);

        const wall4 = new THREE.Mesh(wallGeo, materials.wall);
        wall4.position.set(-5, wallHeight / 2 + 0.5, 0);
        wall4.castShadow = true;
        wall4.receiveShadow = true;
        houseGroup.add(wall4);

        // Roof
        const roofGeo = new THREE.ConeGeometry(9, 5, 4);
        const roof = new THREE.Mesh(roofGeo, materials.roof);
        roof.position.y = wallHeight + 2.5;
        roof.rotation.y = Math.PI / 4;
        roof.castShadow = true;
        roof.receiveShadow = true;
        houseGroup.add(roof);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 3.5, 0.2);
        const door = new THREE.Mesh(doorGeo, materials.door);
        door.position.set(0, 1.75, 4.9);
        door.castShadow = true;
        houseGroup.add(door);

        // Windows
        const winGeo = new THREE.BoxGeometry(1.5, 1.5, 0.1);
        const win1 = new THREE.Mesh(winGeo, materials.window);
        win1.position.set(2, 2.5, 4.95);
        houseGroup.add(win1);

        const win2 = new THREE.Mesh(winGeo, materials.window);
        win2.position.set(-2, 2.5, 4.95);
        houseGroup.add(win2);

        // Chimney
        const chimGeo = new THREE.BoxGeometry(1, 3, 1);
        const chimney = new THREE.Mesh(chimGeo, materials.wall);
        chimney.position.set(3, wallHeight + 3, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // 6. ENVIRONMENT (Ground)
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const ground = new THREE.Mesh(groundGeo, materials.grass);
        ground.rotation.x = -Math.PI / 2;
        ground.position.y = 0;
        ground.receiveShadow = true;
        scene.add(ground);

        // 7. ANIMATION LOOP
        function animate() {
            requestAnimationFrame(animate);

            // Rotate sun slowly
            dirLight.position.x = Math.sin(Date.now() * 0.0001) * 20;
            dirLight.position.z = Math.cos(Date.now() * 0.0001) * 20;

            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  Copy the code block above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in Chrome, Firefox, Safari, or Edge.

